mapper.update:
UPDATE user
phone = #{phone}, password = #{password}, nickname = #{nickName}, real_name = #{realName}, email = #{email}, avatar = #{avatar}, role_type = #{roleType}, status = #{status}, tenant_id = #{tenantId}, last_login_time = #{lastLoginTime}, updated_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT 
FROM user


        AND phone LIKE CONCAT('%', #{phone}, '%')


        AND nickname LIKE CONCAT('%', #{nickName}, '%')


        AND status = #{status}


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}


ORDER BY created_at DESC
